SELECT peia.expenditure_item_id ,--USG pa_cost_distribution_lines_all.line_num, pa_cost_distribution_lines_all.creation_date, pa_cost_distribution_lines_all.created_by, decode(pa_cost_distribution_lines_all.transfer_status_code, 'B', 'G', pa_cost_distribution_lines_all.transfer_status_code) transfer_status_code, DECODE(PEIA.system_linkage_function,'ST',SIGN(NVL(XAL.accounted_dr, 0) - NVL(XAL.accounted_cr, 0)) * ABS(pa_cost_distribution_lines_all.quantity)) AS HOURS, pa_cost_distribution_lines_all.billable_flag, pa_cost_distribution_lines_all.program_update_date, pa_cost_distribution_lines_all.pa_date, dr_gl_code_combinations.code_combination_id dr_code_combination_id, xal.accounting_date as gl_date, xal.accounting_date as recvr_gl_date, pa_cost_distribution_lines_all.reversed_flag, pa_projects_all.ORG_ID,--USG pa_projects_all.PROJECT_ID,--USG pa_cost_distribution_lines_all.task_id,--USG pa_cost_distribution_lines_all.denom_currency_code, 0 as denom_raw_cost, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN pa_cost_distribution_lines_all.denom_burdened_cost ELSE (CASE WHEN nvl(xal.entered_dr,0) <> 0 THEN xal.entered_dr ELSE -(nvl(xal.entered_cr,0)) END) END) as denom_burdened_cost, pa_projects_all.project_currency_code,--USG pa_cost_distribution_lines_all.project_rate_date, pa_cost_distribution_lines_all.project_rate_type, pa_cost_distribution_lines_all.project_exchange_rate, pa_cost_distribution_lines_all.projfunc_cost_exchange_rate, pa_cost_distribution_lines_all.work_type_id, --xah.period_name, jeg_get_gl_period(nvl(xal.accounting_date,xah.accounting_date),pa_cost_distribution_lines_all.org_id) recvr_gl_period_name, --nvl(pa_cost_distribution_lines_all.recvr_pa_period_name,pa_cost_distribution_lines_all.pa_period_name) recvr_pa_period_name, jeg_get_pa_period(nvl(xal.accounting_date,xah.accounting_date),pa_cost_distribution_lines_all.org_id) recvr_pa_period_name, pa_cost_distribution_lines_all.projfunc_cost_rate_type, pa_cost_distribution_lines_all.projfunc_cost_rate_date, pa_projects_all.projfunc_currency_code,--USG peia.expenditure_item_date, peia.EXPENDITURE_TYPE||jeg_get_iws_rec_project(pa_projects_all.segment1,'L',peia.task_id) expenditure_type,--USG nvl(peia.override_to_organization_id, pa_expenditures_all.incurred_by_organization_id) expenditure_organization_id, peia.job_id, peia.system_linkage_function, NULL AS INVENTORY_ITEM_ID, (CASE WHEN peia.system_linkage_function = 'ST' THEN 'HOURS' WHEN peia.system_linkage_function = 'USG' THEN 'USAGE HOURS' WHEN PA_EXPENDITURE_TYPES.UNIT_OF_MEASURE = 'MILEAGE' THEN 'MILEAGE' WHEN peia.system_linkage_function = 'VI' THEN 'DOLLARS' ELSE PA_EXPENDITURE_TYPES.UNIT_OF_MEASURE END) NEW_UNIT_OF_MEASURE, NVL(incurred_by.attribute9,0) as INCURRED_BY_HR_ID, pa_expenditures_all.incurred_by_organization_id, 0 as entered_by, pa_expenditures_all.vendor_id, pa_implementations_all.period_set_name, gl_ledgers.period_set_name, NULL AS PROJECT_ROLE_ID, null resource_organization_id, peia.non_labor_resource, (CASE WHEN peia.system_linkage_function IN ('ER','PJ','BTC') THEN 'FINANCIAL_ELEMENTS' WHEN peia.system_linkage_function IN ('OT','ST') THEN 'PEOPLE' WHEN peia.system_linkage_function = 'INV' THEN 'MATERIAL_ITEMS' WHEN peia.SYSTEM_LINKAGE_FUNCTION = 'VI' AND peia.INVENTORY_ITEM_ID IS NOT NULL THEN 'MATERIAL_ITEMS' WHEN peia.SYSTEM_LINKAGE_FUNCTION = 'VI' AND peia.INVENTORY_ITEM_ID IS NULL AND NVL(LT.ORDER_TYPE_LOOKUP_CODE,'NA') <> 'RATE' THEN 'FINANCIAL_ELEMENTS' WHEN peia.SYSTEM_LINKAGE_FUNCTION = 'VI' AND peia.INVENTORY_ITEM_ID IS NULL AND LT.ORDER_TYPE_LOOKUP_CODE = 'RATE' AND PA_IMPLEMENTATIONS_ALL.XFACE_CWK_TIMECARDS_FLAG='Y' THEN 'PEOPLE' WHEN peia.SYSTEM_LINKAGE_FUNCTION = 'VI' AND peia.INVENTORY_ITEM_ID IS NULL AND LT.ORDER_TYPE_LOOKUP_CODE = 'RATE' AND PA_IMPLEMENTATIONS_ALL.XFACE_CWK_TIMECARDS_FLAG = 'N' THEN 'FINANCIAL_ELEMENTS' WHEN peia.system_linkage_function = 'WIP' AND BOM_RESOURCES.RESOURCE_TYPE = 2 THEN 'PEOPLE' WHEN peia.system_linkage_function = 'WIP' AND BOM_RESOURCES.RESOURCE_TYPE = 1 THEN 'EQUIPMENT' WHEN peia.system_linkage_function = 'WIP' AND NVL(BOM_RESOURCES.RESOURCE_TYPE,0) NOT IN (1,2) THEN 'FINANCIAL_ELEMENTS' WHEN peia.system_linkage_function = 'USG' AND PA_NON_LABOR_RESOURCES.EQUIPMENT_RESOURCE_FLAG = 'N' THEN 'FINANCIAL_ELEMENTS' WHEN peia.system_linkage_function = 'USG' AND NVL(PA_NON_LABOR_RESOURCES.EQUIPMENT_RESOURCE_FLAG,'Y') = 'Y' THEN 'EQUIPMENT' ELSE ' ' END) resource_class, peia.wip_resource_id, pa_cost_distribution_lines_all.line_type, ABS(peia.raw_cost) * SIGN(NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0)) AS PROJFUNC_RAW_COST,--USG pf_Rawcost SIGN(NVL(XAL.accounted_dr, 0) - NVL(XAL.accounted_cr, 0)) * ABS(pa_cost_distribution_lines_all.amount) AS PROJFUNC_BURDENED_COST,--USG pf_burden
ABS(peia.project_raw_cost) * SIGN(NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0)) AS PROJECT_RAW_COST,--USG p_rawcost SIGN(NVL(XAL.accounted_dr, 0) - NVL(XAL.accounted_cr, 0)) * ABS(pa_cost_distribution_lines_all.amount * peia.project_raw_cost/DECODE(peia.raw_cost,0,1,peia.raw_cost)) AS PROJECT_BURDENED_COST,--USG p_burden
peia.raw_cost_rate, peia.burden_cost_rate, peia.bill_job_id, peia.transaction_source, PA_PROJECT_TYPES_ALL.PROJECT_TYPE_CLASS_CODE, '0' AS X_CUSTOM, peia.attribute8, 0 as denom_raw_cost, peia.cost_burden_distributed_flag, peia.bill_hold_flag, (CASE WHEN pa_cost_distribution_lines_all.dr_code_combination_id||xal.ae_line_num = MIN(pa_cost_distribution_lines_all.dr_code_combination_id||xal.ae_line_num) OVER( PARTITION BY xdl.source_distribution_id_num_1, xdl.source_distribution_id_num_1 ORDER BY xal.ae_line_num RANGE UNBOUNDED PRECEDING) THEN peia.burden_cost ELSE 0 END) AS BURDEN_COST, peia.cost_dist_rejection_code, peia.cc_cross_charge_code, peia.cc_ic_processed_code, peia.bill_job_billing_title, peia.attribute2, peia.attribute5, peia.cc_cross_charge_type, JEG_GET_CLASS(pa_projects_all.PROJECT_ID, 'Controlling Performance Unit','C'), NULL AS INVOICE_NUM, NULL AS INVOICE_DATE, null as po_num, peia.non_labor_resource, TRIM(dr_gl_code_combinations.segment3), peia.cc_prvdr_organization_id, peia.cc_recvr_organization_id, TRIM(peia.attribute3), gl_ledgers.currency_code as func_currency_code,--USG NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0) AS FUNC_BURDENED_COST,--USG f_burden ABS(peia.acct_raw_cost) * SIGN(NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0)) AS FUNC_RAW_COST,--USG f_Rawcost pa_tasks.customer_id, xal.ae_line_num, 'LABOR_COST' as source_type, xal.ae_header_id, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN 'Y' ELSE 'N' END) AS WORKSHARE_FLAG, 0 AS PRDR_DENOM_RAW_COST, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN (CASE WHEN nvl(xal.entered_dr,0) <> 0 THEN xal.entered_dr ELSE -(nvl(xal.entered_cr,0)) END) ELSE 0 END) AS PRDR_DENOM_BURDENED_COST, 0 AS PRDR_FUNC_RAW_COST, 0 AS PRDR_PROJFUNC_RAW_COST, 0 AS PRDR_PROJ_RAW_COST, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN (CASE WHEN nvl(xal.accounted_dr,0) <> 0 THEN xal.accounted_dr ELSE -(nvl(xal.accounted_cr,0)) END) ELSE 0 END) AS PRDR_FUNC_BURDENED_COST, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN (CASE WHEN nvl(xal.accounted_dr,0) <> 0 THEN xal.accounted_dr ELSE -(nvl(xal.accounted_cr,0)) END) ELSE 0 END) * NVL(jeg_get_corporate_rate(pa_cost_distribution_lines_all.acct_currency_code,pa_projects_all.projfunc_currency_code,xal.accounting_date),0) AS PRDR_PROJFUNC_BURDENED_COST, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN (CASE WHEN nvl(xal.accounted_dr,0) <> 0 THEN xal.accounted_dr ELSE -(nvl(xal.accounted_cr,0)) END) ELSE 0 END) * NVL(jeg_get_corporate_rate(pa_cost_distribution_lines_all.acct_currency_code,pa_projects_all.project_currency_code,xal.accounting_date),0) AS PRDR_PROJ_BURDENED_COST, (CASE WHEN PEIA.TRANSACTION_SOURCE like '__ STAFF WS' THEN PA_COST_DISTRIBUTION_LINES_ALL.ACCT_CURRENCY_CODE ELSE NULL END) AS PRDR_ACCT_CURR_CODE ,DECODE(PA_COST_DISTRIBUTION_LINES_ALL.billable_flag,'N',jeg_nonbillable_code('01')) AS non_billable_code1 -- Classfication code P ,DECODE(PA_COST_DISTRIBUTION_LINES_ALL.billable_flag,'N',jeg_nonbillable_code('02')) AS non_billable_code2 -- Classfication code R ,DECODE(PA_COST_DISTRIBUTION_LINES_ALL.billable_flag,'N',jeg_nonbillable_code('03')) AS non_billable_code3 -- Classfication code W ,DECODE(PA_COST_DISTRIBUTION_LINES_ALL.billable_flag,'N',jeg_nonbillable_code('04')) AS non_billable_code4 -- Classfication code C ,DECODE(PA_COST_DISTRIBUTION_LINES_ALL.billable_flag,'N',jeg_nonbillable_code('05')) AS non_billable_code5 -- Classfication code X ,jeg_pa_nonb_hours(peia.attribute8,jeg_nonbillable_code('01'),SIGN((NVL(xal.accounted_Dr,0) - NVL(xal.accounted_cr,0))),peia.org_id,PA_COST_DISTRIBUTION_LINES_ALL.billable_flag) AS NB1_Hours -- Classfication Hours P ,jeg_pa_nonb_hours(peia.attribute8,jeg_nonbillable_code('02'),SIGN((NVL(xal.accounted_Dr,0) - NVL(xal.accounted_cr,0))),peia.org_id,PA_COST_DISTRIBUTION_LINES_ALL.billable_flag) AS NB2_Hours -- Classfication Hours R ,jeg_pa_nonb_hours(peia.attribute8,jeg_nonbillable_code('03'),SIGN((NVL(xal.accounted_Dr,0) - NVL(xal.accounted_cr,0))),peia.org_id,PA_COST_DISTRIBUTION_LINES_ALL.billable_flag) AS NB3_Hours -- Classfication Hours W ,jeg_pa_nonb_hours(peia.attribute8,jeg_nonbillable_code('04'),SIGN((NVL(xal.accounted_Dr,0) - NVL(xal.accounted_cr,0))),peia.org_id,PA_COST_DISTRIBUTION_LINES_ALL.billable_flag) AS NB4_Hours -- Classfication Hours C ,jeg_pa_nonb_hours(peia.attribute8,jeg_nonbillable_code('05'),SIGN((NVL(xal.accounted_Dr,0) - NVL(xal.accounted_cr,0))),peia.org_id,PA_COST_DISTRIBUTION_LINES_ALL.billable_flag) AS NB5_Hours -- Classfication Hours X ,CASE WHEN FND_USER.USER_NAME = 'CONVERSION' OR PEIA.TRANSACTION_SOURCE LIKE '%CONVERSION%' OR PEIA.EXPENDITURE_TYPE LIKE 'Conv-%' OR PEIA.BILL_GROUP LIKE 'CH2M-CONVERSION%' THEN 'CONVERSION' ELSE NULL END AS X_CONVERSION_NAME ,PAAF.ASS_ATTRIBUTE3 AS X_ASSIGNED_PU_ID ,peia.ORIG_TRANSACTION_REFERENCE AS X_ORIG_TRANS_REFERENCE ,CASE WHEN INSTR ( peia.attribute8, 'JMC LC') > 1 THEN NEXT_DAY (pa_cost_distribution_lines_all.pa_Date - 1, 'FRIDAY') END as X_CORRECTION_DATE ,case when xah.gl_transfer_status_code ='Y' THEN xah.gl_transfer_Date END AS X_GL_TRANSFER_DATE ,pa_expenditures_all.expenditure_ending_date as X_EXPENDITURE_END_DATE
/* -- (USG columns) pa_projects_all.ORG_ID prj_org_id ,XAL.LEDGER_ID ,pa_projects_all.PROJECT_ID ,pa_projects_all.segment1 Project_number ,dr_gl_code_combinations.segment1 LE ,dr_gl_code_combinations.segment2 account ,dr_gl_code_combinations.segment3 pu ,dr_gl_code_combinations.segment4 s4 ,dr_gl_code_combinations.segment5 s5 ,dr_gl_code_combinations.segment6 s6 --,peia.expenditure_type --,peia.expenditure_type||DECODE(pa_projects_all.segment1,lc_nb_iws,'++'||peia.task_id) ,peia.EXPENDITURE_TYPE||jeg_get_iws_rec_project(pa_projects_all.segment1,'L',peia.task_id) expenditure_type ,pa_cost_distribution_lines_all.billable_flag billable ,jeg_get_pa_period(xal.accounting_date,ln_org_id) ,jeg_get_gl_period(xal.accounting_date,ln_org_id) --,pa_cost_distribution_lines_all.PA_PERIOD_NAME --,pa_cost_distribution_lines_all.GL_PERIOD_NAME ,SUBSTR(pa_cost_distribution_lines_all.GL_PERIOD_NAME, 5) fiscal_year ,DECODE ( SUBSTR(dr_gl_code_combinations.SEGMENT2, 1, 3), 399, 'FLOWTHROUGH', 499, 'FLOWTHROUGH', PACT.CATEGORY ) REPORTING_CATEGORY ,DECODE ( SUBSTR(dr_gl_code_combinations.SEGMENT2, 1, 3) ,399 ,'FLOWTHROUGH' --PALKP.FIN_REP_CATEGORY ,499 ,'FLOWTHROUGH' --PALKP.FIN_REP_CATEGORY ,DECODE ( SUBSTR(dr_gl_code_combinations.SEGMENT2, 1, 3), 399, 'FLOWTHROUGH', 499, 'FLOWTHROUGH', PACT.CATEGORY ) ) FINANCIAL_REPORTING_CATEGORY ,-- DECODE(peia.system_linkage_function,'USG',pa_cost_distribution_lines_all.quantity * sign(NVL(XAL.accounted_dr,0)- NVL(XAL.accounted_cr,0))) hours, 0 HOURS , ABS(peia.raw_cost) * SIGN(NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0)) pf_Rawcost , ABS(peia.acct_raw_cost) * SIGN(NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0)) f_Rawcost , SIGN(NVL(XAL.accounted_dr, 0) - NVL(XAL.accounted_cr, 0)) * ABS(pa_cost_distribution_lines_all.amount) pf_burden , NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0) f_burden , ABS(peia.project_raw_cost) * SIGN(NVL(XAL.accounted_dr, 0)- NVL(XAL.accounted_cr, 0)) p_Rawcost ,SIGN(NVL(XAL.accounted_dr, 0) - NVL(XAL.accounted_cr, 0)) * ABS(pa_cost_distribution_lines_all.amount * peia.project_raw_cost/DECODE(peia.raw_cost,0,1,peia.raw_cost)) p_burden ,gl_ledgers.currency_code ,'COST' record_type ,pa_projects_all.project_currency_code ,pa_projects_all.projfunc_currency_code ,'LABOR DIST' lr3_type ,peia.org_id exp_org_id ,peia.expenditure_item_id ,DECODE(SUBSTR(transaction_source,1,2),'IN',NULL,peia.attribute4) work_location ,pa_cost_distribution_lines_all.task_id
*/
FROM xla_distribution_links XDL ,xla_ae_lines XAL ,xla_ae_headers XAH ,pa_cost_distribution_lines_all pa_cost_distribution_lines_all ,pa_expenditure_items_all peia ,pa_projects_all pa_projects_all ,gl_ledgers gl_ledgers ,gl_code_combinations dr_gl_code_combinations --,JEG_PA_AUTO_ACCT_LKP_SET_V PALKP ,JEG_PA_ACCT_CATEGORIES PACT
/*Newly added tables*/ ,pa_expenditures_all ,per_all_people_f incurred_by ,pa_implementations_all ,PA_PROJECT_TYPES_ALL ,PA_EXPENDITURE_TYPES ,PA_NON_LABOR_RESOURCES ,BOM_RESOURCES ,PO_LINES_ALL POL ,PO_LINE_TYPES_B LT ,pa_tasks ,FND_USER ,PER_ALL_ASSIGNMENTS_F PAAF
WHERE XAH.event_type_code IN ('TOT_BURDENED_COST_DIST' ,'TOT_BURDENED_COST_DIST_ADJ') AND peia.transaction_source = 'FA_DEPREN' /*AND XAH.ae_header_id IN ( SELECT XLAGT.ae_header_id FROM jeg_lr3_xla_ids_gtt XLAGT )*/ AND XAH.ae_header_id = XDL.ae_headeR_id AND XDL.ae_headeR_id = XAL.ae_header_id AND FND_USER.USER_ID(+) = peia.CREATED_BY AND XDL.ae_line_num = XAL.ae_line_num --AND TRUNC(XAL.CREATION_DATE) BETWEEN TRUNC(l_last_completion_Date) -- AND TRUNC(SYSDATE) --AND peia.org_id = p_org_id AND XDL.source_distribution_id_num_1 = pa_cost_distribution_lines_all.expenditure_item_id AND XDL.source_distribution_id_num_2 = pa_cost_distribution_lines_all.line_num AND (pa_cost_distribution_lines_all.line_type = 'D' AND peia.system_linkage_function = 'USG') AND XAL.accounting_class_code = 'COST' AND pa_cost_distribution_lines_all.expenditure_item_id = peia.expenditure_item_id AND peia.project_id = pa_projects_all.project_id AND XAL.ledger_id = gl_ledgers.ledger_id --AND XAL.code_combination_id = dr_gl_code_combinations.code_combination_id --AND 'EType||SType Sup Inv Rev DIR' = -- PALKP.segment_Value_lookup_set_name(+) --AND peia.EXPENDITURE_ITEM_ID = -- PALKP.expenditure_item_id(+) AND gl_ledgers.LEDGER_CATEGORY_CODE = 'PRIMARY' AND dr_gl_code_combinations.SEGMENT2 BETWEEN PACT.ACCOUNT_FROM(+) AND PACT.ACCOUNT_TO(+) AND PACT.TYPE(+) IS NOT NULL AND dr_gl_code_combinations.code_combination_id = XAL.code_combination_id
/*Newly added joins*/ AND peia.expenditure_id = pa_expenditures_all.expenditure_id AND pa_expenditures_all.incurred_by_person_id = incurred_by.person_id (+) AND trunc(pa_expenditures_all.creation_date) <= trunc(incurred_by.effective_end_date (+)) AND trunc(pa_expenditures_all.creation_date) >= trunc(incurred_by.effective_start_date (+)) AND pa_expenditures_all.incurred_by_person_id = PAAF.person_id (+) AND trunc(pa_expenditures_all.creation_date) <= trunc(PAAF.effective_end_date (+)) AND trunc(pa_expenditures_all.creation_date) >= trunc(PAAF.effective_start_date (+)) AND pa_implementations_all.org_id = pa_projects_all.org_id AND PA_PROJECTS_ALL.PROJECT_TYPE = PA_PROJECT_TYPES_ALL.PROJECT_TYPE AND PA_PROJECTS_ALL.ORG_ID = PA_PROJECT_TYPES_ALL.ORG_ID AND peia.EXPENDITURE_TYPE = PA_EXPENDITURE_TYPES.EXPENDITURE_TYPE AND peia.non_labor_resource = PA_NON_LABOR_RESOURCES.non_labor_resource (+) AND peia.wip_resource_id = BOM_RESOURCES.resource_id (+) AND peia.PO_LINE_ID = POL.PO_LINE_ID (+) AND POL.LINE_TYPE_ID = LT.LINE_TYPE_ID (+) AND peia.task_id = pa_tasks.task_id (+) AND XAL.ACCOUNTING_DATE >= to_date('10/01/2016', 'MM/DD/YYYY HH24:MI:SS') AND ( XAH.LAST_UPDATE_DATE >= to_date('$$MV_LAST_EXTRACT_DATE', 'MM/DD/YYYY HH24:MI:SS') OR peia.LAST_UPDATE_DATE >= to_date('$$MV_LAST_EXTRACT_DATE', 'MM/DD/YYYY HH24:MI:SS')) --AND pa_projects_all.SEGMENT1 NOT IN (SELECT DISTINCT PROJECT_NUMBER FROM ($$X_DIVESTCO_SQL)) --Added for Divestiture logic for ECR AND NOT EXISTS (SELECT 1 FROM ($$X_DIVESTCO_SQL) SQ WHERE SQ.PROJECT_NUMBER = pa_projects_all.SEGMENT1 )--Added for Divestiture logic.*/
